import React, { useState, useEffect, useRef } from 'react';
import { User, Property, UserRole } from '../types';
import { Bell, Search, LogOut, Menu, Loader2, Home, MapPin, ChevronRight, X, Sparkles, Building2 } from 'lucide-react';
import { supabase } from '../supabaseClient';

interface HeaderProps {
  user: User;
  onLogout: () => void;
  onOpenSidebar: () => void;
  onViewProperty: (id: string) => void;
}

const Header: React.FC<HeaderProps> = ({ user, onLogout, onOpenSidebar, onViewProperty }) => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<Property[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [unreadApplications, setUnreadApplications] = useState(0);
  const [showNotificationPopup, setShowNotificationPopup] = useState(false);
  const [showPropertyNotification, setShowPropertyNotification] = useState(false);
  const [lastAddedProperty, setLastAddedProperty] = useState<Property | null>(null);
  const searchRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    fetchInitialUnread();

    // Inscrição em tempo real para novas candidaturas e novos imóveis
    const channel = supabase
      .channel('header_notifications')
      // Listener para Candidaturas
      .on('postgres_changes', { event: 'INSERT', table: 'job_applications' }, (payload) => {
        setUnreadApplications(prev => prev + 1);
        setShowNotificationPopup(true);
        setTimeout(() => setShowNotificationPopup(false), 5000);
      })
      // Listener para Novos Imóveis (Notificação para Admins/Gestores)
      .on('postgres_changes', { event: 'INSERT', table: 'properties' }, (payload) => {
        // Apenas notificar se for Admin, CEO ou Gestor
        const adminRoles = [UserRole.ADMIN, UserRole.CEO, UserRole.MANAGER];
        if (adminRoles.includes(user.role)) {
          setLastAddedProperty(payload.new as Property);
          setShowPropertyNotification(true);
          setTimeout(() => setShowPropertyNotification(false), 7000);
        }
      })
      .on('postgres_changes', { event: 'UPDATE', table: 'job_applications' }, () => {
        fetchInitialUnread();
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [user.role]);

  async function fetchInitialUnread() {
    const { count, error } = await supabase
      .from('job_applications')
      .select('*', { count: 'exact', head: true })
      .eq('status', 'Pendente');

    if (!error) setUnreadApplications(count || 0);
  }

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (searchRef.current && !searchRef.current.contains(event.target as Node)) {
        setShowResults(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    const timer = setTimeout(async () => {
      if (query.trim().length < 2) {
        setResults([]);
        setIsSearching(false);
        return;
      }

      setIsSearching(true);
      try {
        const { data, error } = await supabase
          .from('properties')
          .select('*')
          .or(`title.ilike.%${query}%,location.ilike.%${query}%`)
          .limit(5);

        if (!error && data) {
          setResults(data);
        }
      } catch (err) {
        console.error("Search error:", err);
      } finally {
        setIsSearching(false);
        setShowResults(true);
      }
    }, 400);

    return () => clearTimeout(timer);
  }, [query]);

  const handleSelectResult = (id: string) => {
    onViewProperty(id);
    setQuery('');
    setShowResults(false);
  };

  return (
    <header className="h-20 bg-white border-b border-slate-200 flex items-center justify-between px-4 md:px-8 shrink-0 relative z-[60]">
      <div className="flex items-center gap-4 flex-1">
        <button onClick={onOpenSidebar} className="md:hidden text-slate-500 p-2 hover:bg-slate-100 rounded-lg">
          <Menu size={24} />
        </button>

        <div ref={searchRef} className="hidden sm:flex relative max-w-xs md:max-w-md w-full">
          <span className="absolute inset-y-0 left-3 flex items-center text-slate-400">
            {isSearching ? <Loader2 size={18} className="animate-spin text-blue-600" /> : <Search size={18} />}
          </span>
          <input
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onFocus={() => query.length >= 2 && setShowResults(true)}
            placeholder="Pesquisar imóveis (Título ou Local)..."
            className="w-full pl-10 pr-10 py-2.5 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent text-sm font-medium transition-all"
          />
          {query && (
            <button 
              onClick={() => {setQuery(''); setResults([]);}} 
              className="absolute inset-y-0 right-3 flex items-center text-slate-400 hover:text-slate-600"
            >
              <X size={16} />
            </button>
          )}

          {showResults && (query.length >= 2) && (
            <div className="absolute top-full left-0 right-0 mt-2 bg-white rounded-2xl shadow-2xl border border-slate-100 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
              <div className="p-3 bg-slate-50 border-b border-slate-100 flex items-center justify-between">
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Resultados Cloud</span>
                {results.length > 0 && <span className="text-[10px] font-bold text-blue-600 bg-blue-50 px-2 py-0.5 rounded-full">{results.length} encontrados</span>}
              </div>

              <div className="max-h-[350px] overflow-y-auto custom-scrollbar">
                {results.length > 0 ? (
                  results.map((prop) => (
                    <button
                      key={prop.id}
                      onClick={() => handleSelectResult(prop.id)}
                      className="w-full flex items-center gap-4 p-4 hover:bg-slate-50 transition-colors text-left border-b border-slate-50 last:border-0 group"
                    >
                      <img 
                        src={prop.image} 
                        alt="" 
                        className="w-12 h-12 rounded-lg object-cover shadow-sm group-hover:scale-105 transition-transform"
                      />
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-bold text-slate-900 truncate group-hover:text-blue-600 transition-colors">{prop.title}</p>
                        <div className="flex items-center gap-2 text-[10px] text-slate-500 font-medium">
                          <MapPin size={10} className="text-blue-500" />
                          <span className="truncate">{prop.location}</span>
                        </div>
                      </div>
                      <div className="text-right shrink-0">
                        <p className="text-xs font-black text-blue-600">{prop.price.toLocaleString()} MT</p>
                        <ChevronRight size={14} className="text-slate-300 ml-auto mt-1 group-hover:translate-x-1 transition-transform" />
                      </div>
                    </button>
                  ))
                ) : !isSearching ? (
                  <div className="p-8 text-center">
                    <Home size={32} className="mx-auto text-slate-200 mb-2" />
                    <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Nenhum imóvel encontrado</p>
                  </div>
                ) : (
                  <div className="p-8 text-center flex flex-col items-center gap-2">
                    <Loader2 size={24} className="animate-spin text-blue-500" />
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Buscando na Cloud...</p>
                  </div>
                )}
              </div>
            </div>
          )}
        </div>
      </div>

      <div className="flex items-center gap-4 md:gap-6">
        {/* Notificação de Candidatura */}
        {showNotificationPopup && (
          <div className="absolute top-24 right-8 bg-slate-900 text-white p-5 rounded-[2rem] shadow-2xl flex items-center gap-4 animate-in slide-in-from-right-10 duration-500 border border-blue-500/30 z-[70]">
            <div className="p-3 bg-blue-600 rounded-2xl animate-bounce">
              <Sparkles size={20} />
            </div>
            <div>
              <p className="text-xs font-black uppercase tracking-widest">Nova Candidatura!</p>
              <p className="text-[10px] text-slate-400 font-medium">Um novo currículo foi recebido na Cloud.</p>
            </div>
          </div>
        )}

        {/* Notificação de Novo Imóvel (Para Admins) */}
        {showPropertyNotification && lastAddedProperty && (
          <div className="absolute top-24 right-8 bg-white border border-indigo-100 p-5 rounded-[2rem] shadow-[0_20px_50px_rgba(79,70,229,0.15)] flex items-center gap-4 animate-in slide-in-from-right-10 duration-500 z-[70] min-w-[300px]">
            <div className="p-3 bg-indigo-600 text-white rounded-2xl shadow-lg shadow-indigo-600/20 animate-pulse">
              <Building2 size={20} />
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.2em] mb-0.5">Catálogo Atualizado</p>
              <p className="text-sm font-black text-slate-900 truncate leading-tight">{lastAddedProperty.title}</p>
              <p className="text-[9px] text-slate-400 font-bold uppercase mt-1 flex items-center gap-1">
                <MapPin size={8} className="text-indigo-400" /> {lastAddedProperty.location}
              </p>
            </div>
            <button 
              onClick={() => { setShowPropertyNotification(false); onViewProperty(lastAddedProperty.id); }}
              className="p-2 bg-indigo-50 text-indigo-600 rounded-xl hover:bg-indigo-600 hover:text-white transition-all"
              title="Ver Imóvel"
            >
              <ChevronRight size={16} />
            </button>
          </div>
        )}

        <button className="relative p-2 text-slate-500 hover:bg-slate-50 rounded-full transition-all group">
          <Bell size={20} className={unreadApplications > 0 ? "text-blue-600 animate-pulse" : ""} />
          {unreadApplications > 0 && (
            <span className="absolute top-1.5 right-1.5 w-4 h-4 bg-red-500 border-2 border-white rounded-full flex items-center justify-center text-[8px] font-black text-white shadow-sm">
              {unreadApplications > 9 ? '+9' : unreadApplications}
            </span>
          )}
        </button>

        <div className="h-8 w-px bg-slate-200"></div>

        <div className="flex items-center gap-3">
          <div className="text-right hidden sm:block">
            <p className="text-sm font-semibold text-slate-900 leading-none">{user.name}</p>
            <p className="text-xs text-slate-500 mt-1">{user.role}</p>
          </div>
          <img src={user.avatar} alt={user.name} className="w-10 h-10 rounded-xl object-cover ring-2 ring-slate-100" />
          <button 
            onClick={onLogout}
            className="ml-2 p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-xl transition-colors"
            title="Sair do sistema"
          >
            <LogOut size={20} />
          </button>
        </div>
      </div>
    </header>
  );
};

export default Header;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  TrendingUp, TrendingDown, Users, Home, 
  Plus, MessageSquare, Briefcase, 
  Loader2, Wallet, ChevronRight,
  ArrowUpRight, ArrowDownRight, Activity,
  Sparkles, Trash2, Edit3, Save, X as CloseIcon, 
  Cloud, ShieldCheck, Globe, Mail, Clock, UserCheck, AlertTriangle,
  UserPlus, ArrowRight, RefreshCw, Send, Bot
} from 'lucide-react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, 
  ResponsiveContainer, PieChart, Pie, Cell 
} from 'recharts';
import { supabase } from '../supabaseClient';
import { Transaction, Employee, Project, Property, JobApplication } from '../types';
import { getStrategicInsight, chatWithMonteAI } from '../geminiService';
import TodoList from '../components/TodoList';

const DashboardView: React.FC = () => {
  const [stats, setStats] = useState({ 
    revenue: 0, 
    expenses: 0, 
    employees: 0, 
    properties: 0, 
    contacts: 0,
    pendingApps: 0 
  });
  const [recentMessages, setRecentMessages] = useState<any[]>([]);
  const [recentApps, setRecentApps] = useState<JobApplication[]>([]);
  const [loading, setLoading] = useState(true);
  const [dbError, setDbError] = useState<string | null>(null);
  const [aiInsight, setAiInsight] = useState<string>('Analizando pulso da Monte Imobiliária...');

  // AI Chat States
  const [aiChatOpen, setAiChatOpen] = useState(false);
  const [chatInput, setChatInput] = useState('');
  const [chatMessages, setChatMessages] = useState<{role: 'user' | 'ai', text: string}[]>([
    { role: 'ai', text: 'Olá! Sou o Monte AI. Como posso ajudar com a gestão estratégica da Monte Imobiliária hoje?' }
  ]);
  const [isAiTyping, setIsAiTyping] = useState(false);

  useEffect(() => {
    fetchGlobalStats();
  }, []);

  async function fetchGlobalStats() {
    setLoading(true);
    try {
      const [txRes, empRes, propRes, contactRes, msgListRes, appListRes, appCountRes] = await Promise.all([
        supabase.from('transactions').select('*'),
        supabase.from('employees').select('*', { count: 'exact', head: true }),
        supabase.from('properties').select('*', { count: 'exact', head: true }),
        supabase.from('contact_requests').select('*', { count: 'exact', head: true }),
        supabase.from('contact_requests').select('*').order('created_at', { ascending: false }).limit(3),
        supabase.from('job_applications').select('*').order('created_at', { ascending: false }).limit(4),
        supabase.from('job_applications').select('*', { count: 'exact', head: true }).eq('status', 'Pendente')
      ]);

      const txs = txRes.data || [];
      const rev = txs.filter(t => t.type === 'RECEITA').reduce((a, b) => a + Number(b.amount || 0), 0);
      const exp = txs.filter(t => t.type === 'DESPESA').reduce((a, b) => a + Number(b.amount || 0), 0);

      const newStats = {
        revenue: rev, 
        expenses: exp,
        employees: empRes.count || 0,
        properties: propRes.count || 0, 
        contacts: contactRes.count || 0,
        pendingApps: appCountRes.count || 0
      };
      setStats(newStats);
      setRecentMessages(msgListRes.data || []);
      setRecentApps(appListRes.data || []);

      const insight = await getStrategicInsight(`Fluxo: ${rev-exp}MT, Imóveis: ${propRes.count}, Staff: ${empRes.count}`);
      setAiInsight(insight);
    } catch (error: any) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  }

  const handleSendToAI = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!chatInput.trim() || isAiTyping) return;

    const userMsg = chatInput;
    setChatMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setChatInput('');
    setIsAiTyping(true);

    const response = await chatWithMonteAI(userMsg, stats);
    setChatMessages(prev => [...prev, { role: 'ai', text: response }]);
    setIsAiTyping(false);
  };

  const chartData = useMemo(() => [
    { name: 'Receitas', value: stats.revenue, color: '#6366f1' },
    { name: 'Despesas', value: stats.expenses, color: '#f43f5e' }
  ], [stats]);

  if (loading) return (
    <div className="h-full flex flex-col items-center justify-center py-32 gap-6 bg-slate-50">
      <div className="w-16 h-16 bg-indigo-600 rounded-[2rem] flex items-center justify-center p-4 shadow-2xl animate-bounce">
         <img src="https://i.ibb.co/LzfNdf7Y/building-logo.png" className="w-full h-full object-contain brightness-0 invert" alt="Monte Logo" />
      </div>
      <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em] animate-pulse">Sincronizando Monte Imobiliária...</p>
    </div>
  );

  return (
    <div className="space-y-10 animate-in fade-in duration-700 pb-20">
      {/* Header Stat & Insight AI */}
      <div className="flex flex-col xl:flex-row gap-6">
        <div className="flex-1 bg-white px-10 py-8 rounded-[3.5rem] border border-slate-100 shadow-sm flex items-center justify-between">
          <div className="flex items-center gap-6">
             <div className="w-16 h-16 bg-indigo-50 text-indigo-600 rounded-3xl flex items-center justify-center shadow-inner">
               <Bot size={32} />
             </div>
             <div>
                <p className="text-[9px] font-black text-indigo-500 uppercase tracking-widest mb-1 flex items-center gap-2">
                  <Sparkles size={12} className="animate-pulse" /> Monte AI Assistant
                </p>
                <h2 className="text-xl font-black text-slate-900 tracking-tight leading-tight">"{aiInsight}"</h2>
             </div>
          </div>
          <button onClick={() => setAiChatOpen(true)} className="px-6 py-3 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-900 transition-all shadow-xl shadow-indigo-600/20 active:scale-95">Consultar IA</button>
