        <div className="space-y-10">
           {/* Inbox Widget */}
           <div className="bg-slate-900 rounded-[4rem] p-10 text-white shadow-2xl relative overflow-hidden border border-white/5">
              <div className="relative z-10">
                 <div className="flex items-center justify-between mb-10">
