                   <span className="text-[10px] font-black text-indigo-600 uppercase">Receitas</span>
                   <span className="text-lg font-black text-slate-900">{stats.revenue.toLocaleString()} MT</span>
                </div>
                <div className="p-6 bg-rose-50 rounded-3xl flex justify-between items-center">
                   <span className="text-[10px] font-black text-rose-600 uppercase">Despesas</span>
                   <span className="text-lg font-black text-slate-900">{stats.expenses.toLocaleString()} MT</span>
                </div>
             </div>
           </div>
        </div>
      </div>

      {/* Monte AI Overlay Chat */}
      {aiChatOpen && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-xl animate-in fade-in">
           <div className="bg-white rounded-[4rem] w-full max-w-2xl h-[80vh] flex flex-col shadow-2xl relative border-t-[12px] border-indigo-600">
              <button onClick={() => setAiChatOpen(false)} className="absolute top-8 right-8 p-3 bg-slate-50 text-slate-400 hover:text-slate-900 rounded-2xl"><CloseIcon size={24} /></button>

              <div className="p-10 border-b border-slate-50 flex items-center gap-4">
                 <div className="w-14 h-14 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-indigo-500/20">
                    <Bot size={32} />
                 </div>
                 <div>
                    <h3 className="text-2xl font-black text-slate-900 tracking-tight">Monte AI Assistant</h3>
                    <p className="text-[10px] font-black text-indigo-500 uppercase tracking-widest flex items-center gap-2">
                       <ShieldCheck size={12} /> Consultoria Estratégica Autorizada
                    </p>
                 </div>
              </div>

              <div className="flex-1 overflow-y-auto p-10 space-y-6 custom-scrollbar">
                 {chatMessages.map((msg, i) => (
                   <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                      <div className={`max-w-[85%] p-6 rounded-[2.5rem] text-sm font-medium shadow-sm leading-relaxed ${
                        msg.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-slate-50 text-slate-700 rounded-tl-none border border-slate-100'
                      }`}>
                         {msg.text}
                      </div>
                   </div>
                 ))}
                 {isAiTyping && (
                   <div className="flex justify-start animate-pulse">
                      <div className="bg-slate-50 p-4 rounded-3xl rounded-tl-none flex gap-1.5 items-center border border-slate-100">
                         <div className="w-1.5 h-1.5 bg-indigo-600 rounded-full animate-bounce"></div>
                         <div className="w-1.5 h-1.5 bg-indigo-600 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                         <div className="w-1.5 h-1.5 bg-indigo-600 rounded-full animate-bounce [animation-delay:0.4s]"></div>
                      </div>
                   </div>
                 )}
              </div>

              <div className="p-8 border-t border-slate-50">
                 <form onSubmit={handleSendToAI} className="flex gap-3">
                    <input 
                      autoFocus
                      value={chatInput}
                      onChange={e => setChatInput(e.target.value)}
                      placeholder="Pergunte sobre rentabilidade, equipe ou mercado..." 
                      className="flex-1 bg-slate-50 border-none rounded-3xl px-8 py-5 font-bold text-sm outline-none focus:ring-4 focus:ring-indigo-50"
                    />
                    <button type="submit" disabled={isAiTyping || !chatInput.trim()} className="px-8 py-5 bg-indigo-600 text-white rounded-3xl shadow-xl hover:bg-slate-900 transition-all active:scale-95 disabled:opacity-50">
                       <Send size={20} />
                    </button>
                 </form>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default DashboardView;

import React, { useState, useEffect, useRef } from 'react';
import { User, Property, UserRole } from '../types';
import { Bell, Search, LogOut, Menu, Loader2, Home, MapPin, ChevronRight, X, Sparkles, Building2, BellRing } from 'lucide-react';
import { supabase } from '../supabaseClient';

interface HeaderProps {
  user: User;
  onLogout: () => void;
  onOpenSidebar: () => void;
  onViewProperty: (id: string) => void;
}

const NOTIFICATION_SOUND = 'https://assets.mixkit.co/active_storage/sfx/2869/2869-preview.mp3';

const Header: React.FC<HeaderProps> = ({ user, onLogout, onOpenSidebar, onViewProperty }) => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<Property[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [unreadApplications, setUnreadApplications] = useState(0);
  const [showNotificationPopup, setShowNotificationPopup] = useState(false);
  const [showPropertyNotification, setShowPropertyNotification] = useState(false);
  const [lastAddedProperty, setLastAddedProperty] = useState<Property | null>(null);
  const searchRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    audioRef.current = new Audio(NOTIFICATION_SOUND);
    fetchInitialUnread();

    // Inscrição em tempo real para novos eventos
    const channel = supabase
      .channel('header_notifications')
      // Listener para Candidaturas
      .on('postgres_changes', { event: 'INSERT', table: 'job_applications' }, () => {
        setUnreadApplications(prev => prev + 1);
        setShowNotificationPopup(true);
        if (audioRef.current) audioRef.current.play().catch(() => {});
        setTimeout(() => setShowNotificationPopup(false), 5000);
      })
      // Listener para Novos Imóveis (Foco do pedido)
      .on('postgres_changes', { event: 'INSERT', table: 'properties' }, (payload) => {
        const adminRoles = [UserRole.ADMIN, UserRole.CEO, UserRole.MANAGER];
        if (adminRoles.includes(user.role)) {
          setLastAddedProperty(payload.new as Property);
          setShowPropertyNotification(true);
          if (audioRef.current) audioRef.current.play().catch(() => {});
          setTimeout(() => setShowPropertyNotification(false), 8000);
        }
      })
      .on('postgres_changes', { event: 'UPDATE', table: 'job_applications' }, () => {
        fetchInitialUnread();
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [user.role]);

  async function fetchInitialUnread() {
    const { count, error } = await supabase
      .from('job_applications')
      .select('*', { count: 'exact', head: true })
      .eq('status', 'Pendente');

    if (!error) setUnreadApplications(count || 0);
  }

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (searchRef.current && !searchRef.current.contains(event.target as Node)) {
        setShowResults(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    const timer = setTimeout(async () => {
      if (query.trim().length < 2) {
        setResults([]);
        setIsSearching(false);
        return;
      }

      setIsSearching(true);
      try {
        const { data, error } = await supabase
          .from('properties')
          .select('*')
          .or(`title.ilike.%${query}%,location.ilike.%${query}%`)
          .limit(5);

        if (!error && data) {
          setResults(data);
        }
      } catch (err) {
        console.error("Search error:", err);
      } finally {
        setIsSearching(false);
        setShowResults(true);
      }
    }, 400);

    return () => clearTimeout(timer);
  }, [query]);

  const handleSelectResult = (id: string) => {
    onViewProperty(id);
    setQuery('');
    setShowResults(false);
  };

  return (
    <header className="h-20 bg-white border-b border-slate-200 flex items-center justify-between px-4 md:px-8 shrink-0 relative z-[60]">
      <div className="flex items-center gap-4 flex-1">
        <button onClick={onOpenSidebar} className="md:hidden text-slate-500 p-2 hover:bg-slate-100 rounded-lg">
          <Menu size={24} />
        </button>

        <div ref={searchRef} className="hidden sm:flex relative max-w-xs md:max-w-md w-full">
          <span className="absolute inset-y-0 left-3 flex items-center text-slate-400">
            {isSearching ? <Loader2 size={18} className="animate-spin text-blue-600" /> : <Search size={18} />}
          </span>
          <input
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onFocus={() => query.length >= 2 && setShowResults(true)}
            placeholder="Pesquisar imóveis (Título ou Local)..."
            className="w-full pl-10 pr-10 py-2.5 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent text-sm font-medium transition-all"
          />
          {query && (
            <button 
              onClick={() => {setQuery(''); setResults([]);}} 
              className="absolute inset-y-0 right-3 flex items-center text-slate-400 hover:text-slate-600"
            >
              <X size={16} />
            </button>
          )}

          {showResults && (query.length >= 2) && (
            <div className="absolute top-full left-0 right-0 mt-2 bg-white rounded-2xl shadow-2xl border border-slate-100 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
              <div className="p-3 bg-slate-50 border-b border-slate-100 flex items-center justify-between">
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Resultados Cloud</span>
                {results.length > 0 && <span className="text-[10px] font-bold text-blue-600 bg-blue-50 px-2 py-0.5 rounded-full">{results.length} encontrados</span>}
              </div>

              <div className="max-h-[350px] overflow-y-auto custom-scrollbar">
                {results.length > 0 ? (
                  results.map((prop) => (
                    <button
                      key={prop.id}
                      onClick={() => handleSelectResult(prop.id)}
                      className="w-full flex items-center gap-4 p-4 hover:bg-slate-50 transition-colors text-left border-b border-slate-50 last:border-0 group"
                    >
                      <img 
                        src={prop.image} 
                        alt="" 
                        className="w-12 h-12 rounded-lg object-cover shadow-sm group-hover:scale-105 transition-transform"
                      />
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-bold text-slate-900 truncate group-hover:text-blue-600 transition-colors">{prop.title}</p>
                        <div className="flex items-center gap-2 text-[10px] text-slate-500 font-medium">
                          <MapPin size={10} className="text-blue-500" />
                          <span className="truncate">{prop.location}</span>
                        </div>
                      </div>
                      <div className="text-right shrink-0">
                        <p className="text-xs font-black text-blue-600">{prop.price.toLocaleString()} MT</p>
                        <ChevronRight size={14} className="text-slate-300 ml-auto mt-1 group-hover:translate-x-1 transition-transform" />
                      </div>
                    </button>
                  ))
                ) : !isSearching ? (
                  <div className="p-8 text-center">
                    <Home size={32} className="mx-auto text-slate-200 mb-2" />
                    <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Nenhum imóvel encontrado</p>
                  </div>
                ) : (
                  <div className="p-8 text-center flex flex-col items-center gap-2">
                    <Loader2 size={24} className="animate-spin text-blue-500" />
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Buscando na Cloud...</p>
                  </div>
                )}
              </div>
            </div>
          )}
        </div>
      </div>

      <div className="flex items-center gap-4 md:gap-6">
        {/* Notificação de Candidatura */}
        {showNotificationPopup && (
          <div className="absolute top-24 right-8 bg-slate-900 text-white p-5 rounded-[2rem] shadow-2xl flex items-center gap-4 animate-in slide-in-from-right-10 duration-500 border border-blue-500/30 z-[70]">
            <div className="p-3 bg-blue-600 rounded-2xl animate-bounce">
              <Sparkles size={20} />
            </div>
            <div>
              <p className="text-xs font-black uppercase tracking-widest">Nova Candidatura!</p>
              <p className="text-[10px] text-slate-400 font-medium">Um novo currículo foi recebido na Cloud.</p>
            </div>
          </div>
        )}

        {/* Notificação de Novo Imóvel (Dashboard Administrativo) */}
        {showPropertyNotification && lastAddedProperty && (
          <div className="fixed top-24 right-8 bg-white border border-indigo-100 p-6 rounded-[2.5rem] shadow-[0_30px_60px_rgba(79,70,229,0.2)] flex items-center gap-5 animate-in slide-in-from-right-10 duration-500 z-[100] min-w-[320px]">
            <div className="relative">
              <div className="p-4 bg-indigo-600 text-white rounded-2xl shadow-lg shadow-indigo-600/30 animate-pulse">
                <Building2 size={24} />
              </div>
              <div className="absolute -top-1 -right-1 w-4 h-4 bg-rose-500 border-2 border-white rounded-full"></div>
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.2em] mb-1 flex items-center gap-2">
                <BellRing size={10} /> Novo no Catálogo
              </p>
              <p className="text-sm font-black text-slate-900 truncate leading-tight">{lastAddedProperty.title}</p>
              <p className="text-[9px] text-slate-400 font-bold uppercase mt-1.5 flex items-center gap-1">
                <MapPin size={10} className="text-indigo-400" /> {lastAddedProperty.location}
              </p>
            </div>
            <button 
              onClick={() => { setShowPropertyNotification(false); onViewProperty(lastAddedProperty.id); }}
              className="p-3 bg-indigo-50 text-indigo-600 rounded-xl hover:bg-indigo-600 hover:text-white transition-all shadow-sm active:scale-90"
              title="Visualizar Detalhes"
            >
              <ChevronRight size={18} />
            </button>
            <button 
              onClick={() => setShowPropertyNotification(false)}
              className="absolute top-4 right-4 text-slate-300 hover:text-slate-500 transition-colors"
            >
              <X size={14} />
            </button>
          </div>
        )}

        <button className="relative p-2 text-slate-500 hover:bg-slate-50 rounded-full transition-all group">
          <Bell size={20} className={unreadApplications > 0 ? "text-blue-600 animate-pulse" : ""} />
          {unreadApplications > 0 && (
            <span className="absolute top-1.5 right-1.5 w-4 h-4 bg-red-500 border-2 border-white rounded-full flex items-center justify-center text-[8px] font-black text-white shadow-sm">
              {unreadApplications > 9 ? '+9' : unreadApplications}
            </span>
          )}
        </button>

        <div className="h-8 w-px bg-slate-200"></div>

        <div className="flex items-center gap-3">
          <div className="text-right hidden sm:block">
            <p className="text-sm font-semibold text-slate-900 leading-none">{user.name}</p>
            <p className="text-xs text-slate-500 mt-1">{user.role}</p>
          </div>
          <img src={user.avatar} alt={user.name} className="w-10 h-10 rounded-xl object-cover ring-2 ring-slate-100" />
          <button 
            onClick={onLogout}
            className="ml-2 p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-xl transition-colors"
            title="Sair do sistema"
          >
            <LogOut size={20} />
          </button>
        </div>
      </div>
    </header>
  );
};

export default Header;
